cd /c/Users/gabri/Desktop/historia && node -e "
const fs = require('fs');
const html = fs.readFileSync('index.html', 'utf8');

// Count data-certeza in periodo-nacional section
const section = html.match(/<section id=\"periodo-nacional\"[\s\S]*?<\/section>/);
if (!section) { console.log('SECTION NOT FOUND'); process.exit(1); }
const s = section[0];

const dataCerteza = (s.match(/data-certeza=/g) || []).length;
const cardImages = (s.match(/<img/g) || []).length;
const eventsGridCerteza = s.includes('events-grid--certeza');
const alberdQuote = s.includes('alberdi-quote');
const citeElements = (s.match(/<cite/g) || []).length;
const blockquote = s.includes('blockquote');
const opinCard = s.includes('card-opinion');
const hechoCards = (s.match(/card-hecho/g) || []).length;
const nacionalTimeline = html.includes('nacional-timeline');
const timelineMarkers = (html.match(/nacional-timeline__marker/g) || []).length;
const revealClass = html.includes('nacional-timeline reveal');
const alberdArc = s.includes('1884') && s.includes('diputado') && s.includes('legado');
const imgError = s.includes('img-error') || s.includes('img-fallback');

console.log('data-certeza attributes:', dataCerteza);
console.log('card-image img elements:', cardImages);
console.log('events-grid--certeza present:', eventsGridCerteza);
console.log('alberdi-quote present:', alberdQuote);
console.log('<cite> elements:', citeElements);
console.log('blockquote present:', blockquote);
console.log('card-opinion present:', opinCard);
console.log('card-hecho present (count):', hechoCards);
console.log('nacional-timeline present:', nacionalTimeline);
console.log('timeline markers (doubled for open/close):', timelineMarkers, '→ unique:', timelineMarkers);
console.log('reveal class on timeline:', revealClass);
console.log('Alberdi arc (1884+diputado+legado):', alberdArc);
console.log('img-error/img-fallback present:', imgError);
"

cd /c/Users/gabri/Desktop/historia && node -e "
const fs = require('fs');
const html = fs.readFileSync('index.html', 'utf8');
// timeline markers: each marker div has class nacional-timeline__marker - count div occurrences 
const markers = (html.match(/class=\"nacional-timeline__marker/g) || []).length;
console.log('distinct .nacional-timeline__marker div openers:', markers);
// reveal-delay check
const delays = html.match(/--reveal-delay: \d+ms/g) || [];
console.log('reveal delays in periodo-nacional section:', delays.filter(d => true));
// stagger on 7 cards
const section = html.match(/<section id=\"periodo-nacional\"[\s\S]*?<\/section>/)[0];
const sDelays = section.match(/--reveal-delay: \d+ms/g) || [];
console.log('stagger delays in section:', sDelays);
// card-nota-historiografica
const notaH = (section.match(/card-nota-historiografica/g) || []).length;
console.log('card-nota-historiografica count:', notaH);
// card-nota-certeza
const notaC = (section.match(/card-nota-certeza/g) || []).length;
console.log('card-nota-certeza count:', notaC);
// img-attribution
const imgAttr = (section.match(/img-attribution/g) || []).length;
console.log('img-attribution count:', imgAttr);
"

cd /c/Users/gabri/Desktop/historia && node -e "
const fs = require('fs');
const html = fs.readFileSync('index.html', 'utf8');
// Check prefers-reduced-motion in styles
const css = fs.readFileSync('styles.css', 'utf8');
const pmBlocks = (css.match(/prefers-reduced-motion/g) || []).length;
console.log('prefers-reduced-motion blocks in CSS:', pmBlocks);
// Verify nacional section has 7 articles
const articles = (html.match(/<article class=\"event-card/g) || []);
const section = html.match(/<section id=\"periodo-nacional\"[\s\S]*?<\/section>/)[0];
const sectionArticles = (section.match(/<article class=\"event-card/g) || []).length;
console.log('event-card articles in #periodo-nacional:', sectionArticles);
// Check certeza distribution
const hechoInSection = (section.match(/data-certeza=\"hecho\"/g) || []).length;
const opinionInSection = (section.match(/data-certeza=\"opinion\"/g) || []).length;
const opinionAccentInSection = (section.match(/data-certeza=\"opinión\"/g) || []).length;
console.log('data-certeza=hecho:', hechoInSection);
console.log('data-certeza=opinion (no accent):', opinionInSection);
console.log('data-certeza=opinión (accent):', opinionAccentInSection);
// Total certeza types represented
console.log('certeza types:', hechoInSection > 0 ? 'hecho ' : '', opinionInSection + opinionAccentInSection > 0 ? 'opinión' : '');
"
